targets.expr:
(
  sum(
    rate(okg_network_calls_total{
      span_name=~"$span",
      game_kruise_io_network_status="ready"
    }[$__rate_interval])
  ) by (game_kruise_io_network_plugin_name, cloud_provider)
)
/
clamp_min(
  sum(
    rate(okg_network_calls_total{
      span_name=~"$span"
    }[$__rate_interval])
  ) by (game_kruise_io_network_plugin_name, cloud_provider),
  1e-6
) * 100

histogram_quantile(
  0.95,
  sum(
    rate(okg_network_duration_seconds_bucket{
      game_kruise_io_network_plugin_name=~"$plugin",
      cloud_provider=~"$cloud"
    }[$__rate_interval])
  ) by (le, span_name)
)

(
  sum(
    rate(okg_network_calls_total{
      span_name=~"$span",
      game_kruise_io_network_status="waiting"
    }[$__rate_interval])
  ) by (game_kruise_io_network_plugin_name, cloud_provider)
)
/
clamp_min(
  sum(
    rate(okg_network_calls_total{
      span_name=~"$span"
    }[$__rate_interval])
  ) by (game_kruise_io_network_plugin_name, cloud_provider),
  1e-6
) * 100

sum(
  rate(okg_network_duration_seconds_sum{
    game_kruise_io_network_plugin_name=~"$plugin",
    cloud_provider=~"$cloud"
  }[$__rate_interval])
) by (span_name)
/
sum(
  rate(okg_network_duration_seconds_count{
    game_kruise_io_network_plugin_name=~"$plugin",
    cloud_provider=~"$cloud"
  }[$__rate_interval])
) by (span_name)

(
  sum(
    rate(okg_network_calls_total{
      span_name=~"$span",
      game_kruise_io_network_status="not_ready"
    }[$__rate_interval])
  ) by (game_kruise_io_network_plugin_name, cloud_provider)
)
/
clamp_min(
  sum(
    rate(okg_network_calls_total{
      span_name=~"$span"
    }[$__rate_interval])
  ) by (game_kruise_io_network_plugin_name, cloud_provider),
  1e-6
) * 100

histogram_quantile(
  0.95,
  sum(
    rate(okg_network_duration_seconds_bucket{
      span_name=~"$span",
      cloud_provider=~"$cloud"
    }[$__rate_interval])
  ) by (le, game_kruise_io_network_plugin_name)
)

(
  sum by (game_kruise_io_network_plugin_name, cloud_provider) (
    rate(okg_network_calls_total{
      span_name=~"$span",
      status_code=~"STATUS_CODE_ERROR|ERROR"
    }[$__rate_interval])
  )
or
  sum by (game_kruise_io_network_plugin_name, cloud_provider) (
    rate(okg_network_calls_total{
      span_name=~"$span",
      game_kruise_io_network_status="error"
    }[$__rate_interval])
  )
)
/ clamp_min(
  sum by (game_kruise_io_network_plugin_name, cloud_provider) (
    rate(okg_network_calls_total{span_name=~"$span"}[$__rate_interval])
  ),
  1e-6
) * 100

histogram_quantile(
  0.95,
  sum(
    rate(okg_network_duration_seconds_bucket{
      game_kruise_io_network_plugin_name=~"$plugin",
      span_name=~"$span"
    }[$__rate_interval])
  ) by (le, game_kruise_io_network_status)
)
